node - <<'NODE'
const https = require('https');
const url='https://api.github.com/repos/jj-vcs/jj/releases/latest';
https.get(url,{headers:{'User-Agent':'node'}},res=>{
  let data='';
  res.on('data',d=>data+=d);
  res.on('end',()=>{
    const json=JSON.parse(data);
    const assets=json.assets||[];
    for(const a of assets){
      const name=a.name||'';
      if(name.includes('unknown-linux-musl') && (name.includes('x86_64')||name.includes('amd64'))){
        console.log(name+' '+a.browser_download_url);
      }
    }
  });
}).on('error',err=>{console.error(err); process.exit(1);});
